// src/modules/projects/routes.js
const express = require('express');
const router = express.Router();
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const project = await projectsService.getProjectById(projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const { name } = req.body;
    if (!name || typeof name !== 'string' || name.trim() === '') {
      return sendError(res, 400, 'INVALID_NAME', 'Invalid project name');
    }
    const newProject = await projectsService.createProject(name);
    res.status(201).json({ project: newProject });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');

const projectsStore = {};

async function getAllProjects() {
  return Object.values(projectsStore);
}

async function createProject(name) {
  const project = { id: randomUUID(), name };
  projectsStore[project.id] = project;
  return project;
}

async function getProjectById(projectId) {
  return projectsStore[projectId];
}

module.exports = { getAllProjects, createProject, getProjectById };

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

async function addTask(projectId, task) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const newTask = { id: randomUUID(), status: 'todo', ...task };
  project.tasks.push(newTask);
  await projectsService.updateProject(projectId, project);
  return newTask;
}

async function getTasksByProjectId(projectId) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  return project.tasks || [];
}

async function updateTask(projectId, taskId, updates) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const taskIndex = project.tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  project.tasks[taskIndex] = { ...project.tasks[taskIndex], ...updates };
  await projectsService.updateProject(projectId, project);
  return project.tasks[taskIndex];
}

module.exports = {
  addTask,
  getTasksByProjectId,
  updateTask,
};

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

async function addMember(projectId, member) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const existingMember = project.members.find(m => m.userId === member.userId);
  if (existingMember) {
    throw { code: 'DUPLICATE_MEMBER', message: 'Member already exists in this project' };
  }

  const newMember = { id: randomUUID(), ...member };
  project.members.push(newMember);
  await projectsService.updateProject(projectId, project);
  return newMember;
}

module.exports = {
  addMember,
};

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

async function addComment(projectId, taskId, comment) {
  const task = await tasksService.getTaskById(projectId, taskId);
  if (!task) {
    return null;
  }

  const newComment = { id: randomUUID(), ...comment };
  task.comments.push(newComment);
  await tasksService.updateTask(projectId, taskId, task);
  return newComment;
}

module.exports = {
  addComment,
};

// src/lib/errors.js
function sendError(res, statusCode, code, message) {
  res.status(statusCode).json({ error: { code, message } });
}

module.exports = { sendError };

